  ('optometrist-moex-01564', 'optometrist', 'optometrist-moex-109-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '驗光所及驗光人員之執行業務紀錄，下列敘述何者正確？①驗光人員應依當事人要求提供驗光結果報', '["驗光人員執行業務應製作紀錄，簽 名或蓋章及加註執行年、月、日，違反者處新臺幣二萬元以上十萬元以下罰鍰", "對醫師開具之照會 單或醫囑單應妥為保管，並至少保存三年", "驗光人員法第20條規定驗光所執行業務之紀錄應妥為 保管，違反者處新臺幣一萬元以上五萬元以下罰鍰", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:48+00:00", "source_pdf_sha1": "bbde246e8075", "answer_pdf_sha1": "9c4914153e8c", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "401", "s": "1501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 47, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
