  ('optometrist-moex-01568', 'optometrist', 'optometrist-moex-109-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '用散光鐘面圖（clockdialchart）做散光檢查時，下列檢查步驟何者不合適？', '["在視網膜檢影鏡檢查結束後，將散光的部分去除，再使用散光鐘面圖做散光檢查", "一律都霧視0.50D以保障最小錯亂圓接近視網膜上", "從患者看散光圖形上的清楚線位置來判斷患者的負散光軸", "增加負散光軸上的散光度數使散光圖形上的線條都一樣清楚"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:48+00:00", "source_pdf_sha1": "2dd083f86c1c", "answer_pdf_sha1": "34cc29db58c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "109060", "c": "401", "s": "0803", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "109", "exam_name": "109年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
